def find_first_last(nums, target):
    def find_left(nums, target):
        low, high = 0, len(nums) - 1
        result = -1
        while low <= high:
            mid = (low + high) // 2
            if nums[mid] == target:
                result = mid
                high = mid - 1
            elif nums[mid] < target:
                low = mid + 1
            else:
                high = mid - 1
        return result

    def find_right(nums, target):
        low, high = 0, len(nums) - 1
        result = -1
        while low <= high:
            mid = (low + high) // 2
            if nums[mid] == target:
                result = mid
                low = mid + 1
            elif nums[mid] < target:
                low = mid + 1
            else:
                high = mid - 1
        return result

    return [find_left(nums, target), find_right(nums, target)]

print(find_first_last([1, 2, 2, 2, 3, 4], 2))
print(find_first_last([1, 3, 5, 7], 5))
print(find_first_last([1, 3, 5, 7], 6))

