from collections import deque

def hot_potato(names, num):
    queue = deque(names)
    while len(queue) > 1:
        for _ in range(num - 1):
            queue.append(queue.popleft())
        queue.popleft()
    return queue[0]

print(hot_potato(["Alice", "Bob", "Charlie", "Diana", "Eve"], 3))
print(hot_potato(["A", "B", "C", "D"], 2))

class MinStack:
    def __init__(self):
        self.stack = []
        self.min_stack = []

    def push(self, val):
        self.stack.append(val)
        if not self.min_stack or val <= self.min_stack[-1]:
            self.min_stack.append(val)

    def pop(self):
        val = self.stack.pop()
        if val == self.min_stack[-1]:
            self.min_stack.pop()
        return val

    def top(self):
        return self.stack[-1]

    def get_min(self):
        return self.min_stack[-1]

ms = MinStack()
ms.push(5)
ms.push(3)
ms.push(7)
ms.push(1)
print(ms.get_min())
ms.pop()
print(ms.get_min())
print(ms.top())

